67	
68	library	IEEE;
69	use			IEEE.std_logic_1164.all;
70	use			IEEE.numeric_std.all;
71	
72	library	poc;
73	use			PoC.utils.all;
74	use			poc.ocram.all; -- "all" required by Quartus RTL simulation
75	
76	
77	entity fifo_ic_got is
78	  generic (
79	    D_BITS         : positive;          -- Data Width
80	    MIN_DEPTH      : positive;          -- Minimum FIFO Depth
81	    DATA_REG       : boolean := false;  -- Store Data Content in Registers
82	    OUTPUT_REG     : boolean := false;  -- Registered FIFO Output
83	    ESTATE_WR_BITS : natural := 0;      -- Empty State Bits
84	    FSTATE_RD_BITS : natural := 0       -- Full State Bits
85	  );
86	  port (
87	    -- Write Interface
88	    clk_wr    : in  std_logic;
89	    rst_wr    : in  std_logic;
90	    put       : in  std_logic;
91	    din       : in  std_logic_vector(D_BITS-1 downto 0);
92	    full      : out std_logic;
93	    estate_wr : out std_logic_vector(imax(ESTATE_WR_BITS-1, 0) downto 0);
94	
95	    -- Read Interface
96	    clk_rd    : in  std_logic;
97	    rst_rd    : in  std_logic;
98	    got       : in  std_logic;
99	    valid     : out std_logic;
100	    dout      : out std_logic_vector(D_BITS-1 downto 0);
101	    fstate_rd : out std_logic_vector(imax(FSTATE_RD_BITS-1, 0) downto 0)
102	  );
103	end entity fifo_ic_got;
104	
105	
106	architecture rtl of fifo_ic_got is
107	
108	  -- Constants
109	  constant A_BITS : positive := log2ceilnz(MIN_DEPTH);
110	  constant AN     : positive := A_BITS + 1;
111	
112	  -- Registers, clk_wr domain
113	  signal IP1 : std_logic_vector(AN-1 downto 0);                     -- IP + 1
114	  signal IP0 : std_logic_vector(AN-1 downto 0) := (others => '0');  -- Write Pointer IP
115	  signal IPz : std_logic_vector(AN-1 downto 0) := (others => '0');  -- IP delayed by one clock
116		signal OPs : std_logic_vector(AN-1 downto 0) := (others => '0');  -- Sync stage: OP0 -> OPc
117	  signal OPc : std_logic_vector(AN-1 downto 0) := (others => '0');  -- Copy of OP
118	  signal Ful : std_logic                       := '0';              -- RAM full
119	
120	  -- Registers, clk_rd domain
121	  signal OP1 : std_logic_vector(AN-1 downto 0);                     -- OP + 1
122	  signal OP0 : std_logic_vector(AN-1 downto 0) := (others => '0');  -- Read Pointer OP
123	  signal IPs : std_logic_vector(AN-1 downto 0) := (others => '0');  -- Sync stage: IPz -> IPc
124	  signal IPc : std_logic_vector(AN-1 downto 0) := (others => '0');  -- Copy of IP
125	  signal Avl : std_logic                       := '0';              -- RAM Data available
126	  signal Vld : std_logic                       := '0';              -- Output Valid
127	
128	  -- Memory Connectivity
129	  signal wa   : unsigned(A_BITS-1 downto 0);
130	  signal di   : std_logic_vector(D_BITS-1 downto 0);
131	  signal puti : std_logic;
132	
133	  signal ra   : unsigned(A_BITS-1 downto 0);
134	  signal do   : std_logic_vector(D_BITS-1 downto 0);
135	  signal geti : std_logic;
136	
137	  signal goti : std_logic;              -- Internal Read ACK
138	
139	begin
140	
141	  -----------------------------------------------------------------------------
142	  -- Write clock domain
143	  -----------------------------------------------------------------------------
144	  blkIP: block
145	    signal Cnt : unsigned(AN-1 downto 0) := to_unsigned(1, AN);
146	  begin
147	    process(clk_wr)
148	    begin
149	      if rising_edge(clk_wr) then
150	        if rst_wr = '1' then
151	          Cnt <= to_unsigned(1, AN);
152	        elsif puti = '1' then
153	          Cnt <= Cnt + 1;
154	        end if;
155	      end if;
156	    end process;
157	    IP1 <= std_logic_vector(Cnt(A_BITS) & (Cnt(A_BITS-1 downto 0) xor ('0' & Cnt(A_BITS-1 downto 1))));
158	  end block blkIP;
159	
160	  -- Update Write Pointer upon puti
161	  process(clk_wr)
162	  begin
163	    if rising_edge(clk_wr) then
164	      if rst_wr = '1' then
165	        IP0 <= (others => '0');
166	        IPz <= (others => '0');
167					OPs <= (others => '0');
168	        OPc <= (others => '0');
169	        Ful <= '0';
170	      else
171	        IPz <= IP0;
172	        OPs <= OP0;
173	        OPc <= OPs;
174	        if puti = '1' then
175	          IP0 <= IP1;
176	          if IP1(A_BITS-1 downto 0) = OPc(A_BITS-1 downto 0) then
177	            Ful <= '1';
178	          else
179	            Ful <= '0';
180	          end if;
181	        end if;
182	        if Ful = '1' then
183	          if IP0 = (not OPc(A_BITS) & OPc(A_BITS-1 downto 0)) then
184	            Ful <= '1';
185	          else
186	            Ful <= '0';
187	          end if;
188	        end if;
189	      end if;
190	    end if;
191	  end process;
192	  puti <= put and not Ful;
193	  full <= Ful;
194	
195	  di <= din;
196	  wa <= unsigned(IP0(A_BITS-1 downto 0));
197	
198	  -----------------------------------------------------------------------------
199	  -- Read clock domain
200	  -----------------------------------------------------------------------------
201	  blkOP: block
202	    signal Cnt : unsigned(AN-1 downto 0) := to_unsigned(1, AN);
203	  begin
204	    process(clk_rd)
205	    begin
206	      if rising_edge(clk_rd) then
207	        if rst_rd = '1' then
208	          Cnt <= to_unsigned(1, AN);
209	        elsif geti = '1' then
210	          Cnt <= Cnt + 1;
211	        end if;
212	      end if;
213	    end process;
214	    OP1 <= std_logic_vector(Cnt(A_BITS) & (Cnt(A_BITS-1 downto 0) xor ('0' & Cnt(A_BITS-1 downto 1))));
215	  end block blkOP;
216	
217	  process(clk_rd)
218	  begin
219	    if rising_edge(clk_rd) then
220	      if rst_rd = '1' then
221	        OP0 <= (others => '0');
222					IPs <= (others => '0');
223	        IPc <= (others => '0');
224	        Avl <= '0';
225	        Vld <= '0';
226	      else
227	        IPs <= IPz;
228	        IPc <= IPs;
229	        if geti = '1' then
230	          OP0 <= OP1;
231	          if OP1(A_BITS-1 downto 0) = IPc(A_BITS-1 downto 0) then
232	            Avl <= '0';
233	          else
234	            Avl <= '1';
235	          end if;
236	          Vld <= '1';
237	        elsif goti = '1' then
238	          Vld <= '0';
239	        end if;
240	
241	        if Avl = '0' then
242	          if OP0 = IPc then
243	            Avl <= '0';
244	          else
245	            Avl <= '1';
246	          end if;
247	        end if;
248	
249	      end if;
250	    end if;
251	  end process;
252	  geti <= (not Vld or goti) and Avl;
253	  ra   <= unsigned(OP0(A_BITS-1 downto 0));
254	
255	  -----------------------------------------------------------------------------
256	  -- Add register to data output
257	  --
258	  -- Not needed if DATA_REG = true, because "dout" is already feed from a
259	  -- register in that case.
260	  -----------------------------------------------------------------------------
261	  genRegN: if DATA_REG or not OUTPUT_REG generate
262	    goti  <= got;
263	    dout  <= do;
264	    valid <= Vld;
265	  end generate genRegN;
266	  genRegY: if (not DATA_REG) and OUTPUT_REG generate
267	    signal Buf  : std_logic_vector(D_BITS-1 downto 0) := (others => '-');
268	    signal VldB : std_logic := '0';
269	  begin
270	   process(clk_rd)
271	   begin
272	     if rising_edge(clk_rd) then
273	       if rst_rd = '1' then
274	         Buf  <= (others => '-');
275	         VldB <= '0';
276	       elsif goti = '1' then
277	         Buf  <= do;
278	         VldB <= Vld;
279	       end if;
280	     end if;
281	   end process;
282	   goti  <= not VldB or got;
283	   dout  <= Buf;
284	   valid <= VldB;
285	  end generate genRegY;
286	
287	  -----------------------------------------------------------------------------
288	  -- Fill State
289	  -----------------------------------------------------------------------------
290	  -- Write Clock Domain
291	  gEstateWr: if ESTATE_WR_BITS >= 1 generate
292	    signal  d : unsigned(A_BITS-1 downto 0);
293	  begin
294	    d         <= unsigned(gray2bin(OPc(A_BITS-1 downto 0))) + not unsigned(gray2bin(IP0(A_BITS-1 downto 0)));
295	    estate_wr <= (others => '0') when Ful = '1' else
296	                 std_logic_vector(d(d'left downto d'left-ESTATE_WR_BITS+1));
297	  end generate gEstateWr;
298	  gNoEstateWr: if ESTATE_WR_BITS = 0 generate
299	    estate_wr <= "X";
300	  end generate gNoEstateWr;
301	
302	  -- Read Clock Domain
303	  gFstateRd: if FSTATE_RD_BITS >= 1 generate
304	    signal  d : unsigned(A_BITS-1 downto 0);
305	  begin
306	    d         <= unsigned(gray2bin(IPc(A_BITS-1 downto 0))) + not unsigned(gray2bin(OP0(A_BITS-1 downto 0)));
307	    fstate_rd <= (others => '0') when Avl = '0' else
308	                 std_logic_vector(d(d'left downto d'left-FSTATE_RD_BITS+1));
309	  end generate gFstateRd;
310	  gNoFstateRd: if FSTATE_RD_BITS = 0 generate
311	    fstate_rd <= "X";
312	  end generate gNoFstateRd;
313	
314	  -----------------------------------------------------------------------------
315	  -- Memory Instantiation
316	  -----------------------------------------------------------------------------
317	  gLarge: if not DATA_REG generate
318	    ram : entity PoC.ocram_sdp
319	      generic map (
320	        A_BITS => A_BITS,
321	        D_BITS => D_BITS
322	        )
323	      port map (
324	        wclk   => clk_wr,
325	        rclk   => clk_rd,
326	        wce    => '1',
327	        rce    => geti,
328	        we     => puti,
329	        ra     => ra,
330	        wa     => wa,
331	        d      => di,
332	        q      => do
333	        );
