37	library IEEE;
38	use IEEE.std_logic_1164.all;
39	
40	library	PoC;
41	use			Poc.utils.all;
42	
43	
44	entity fifo_shift is
45	  generic (
46	    D_BITS    : positive;               -- Data Width
47	    MIN_DEPTH : positive                -- Minimum FIFO Size in Words
48	  );
49	  port (
50	    -- Global Control
51	    clk : in std_logic;
52	    rst : in std_logic;
53	
54	    -- Writing Interface
55	    put : in  std_logic;                            -- Write Request
56	    din : in  std_logic_vector(D_BITS-1 downto 0);  -- Input Data
57	    ful : out std_logic;                            -- Capacity Exhausted
58	
59	    -- Reading Interface
60	    got  : in  std_logic;                            -- Read Done Strobe
61	    dout : out std_logic_vector(D_BITS-1 downto 0);  -- Output Data
62	    vld  : out std_logic                             -- Data Valid
63	  );
64	end entity fifo_shift;
65	
66	library IEEE;
67	use IEEE.numeric_std.all;
68	
69	library poc;
